  buildEventIndex,
  defaultEventOrder,
  eventsOverlap,
  findResource,
  flattenResources,
  getDayKey,
  getDayTotalMinutes,
  getGanttDateRange,
  getLaneKey,
  getRangeKey,
  MIN_PACK_SLOT,
  packTimedSegments,
  rangesIntersect,
  reorderResources,
