  return (
    <NavTooltip content={tooltip === undefined ? defaultTooltip : tooltip}>
      <Button
        variant={nav.variant}
        size={nav.size}
        data-slot="gantt-nav-today"
        data-active={isToday || undefined}
        className={cn(className)}
        onClick={today}
        render={render}
        {...props}
      >
        {children ?? settings.i18n.labels.today}
      </Button>
    </NavTooltip>
  )
}

